// NEON PhaseDial kernels for fixed PhaseDialDimensions (128) complex128 vectors.
// Each complex128 is stored as [real, imag] in a 16-byte lane (V0.D2).

#include "textflag.h"

#define VFADD_D2(m, n, d) WORD $(0x4E60D400 | ((m) << 16) | ((n) << 5) | (d))
#define VFMUL_D2(m, n, d) WORD $(0x4E60DC00 | ((m) << 16) | ((n) << 5) | (d))
#define FADDP_D(n, d)     WORD $(0x7E70D800 | ((n) << 5) | (d))

// func DialEnergy128NEONAsm(dial *complex128) float64
TEXT ·DialEnergy128NEONAsm(SB), NOSPLIT, $0-16
	MOVD dial+0(FP), R0

	VEOR V16.B16, V16.B16, V16.B16
	VEOR V17.B16, V17.B16, V17.B16
	MOVD $128, R1

dial_energy_loop:
	VLD1.P 16(R0), [V0.D2]
	VFMUL_D2(0, 0, 4)
	VFADD_D2(4, 16, 16)
	SUB  $1, R1
	CBNZ R1, dial_energy_loop

	VFADD_D2(17, 16, 16)
	FADDP_D(16, 0)
	FMOVD F0, ret+8(FP)
	RET

// func DialNormalize128NEONAsm(dial *complex128)
TEXT ·DialNormalize128NEONAsm(SB), NOSPLIT, $0-8
	MOVD dial+0(FP), R0

	FMOVD $0.0, F16
	MOVD R0, R1
	MOVD $128, R2

dial_norm_energy:
	FMOVD (R1), F0
	FMOVD 8(R1), F1
	FMULD F0, F0, F2
	FMULD F1, F1, F3
	FADDD F3, F2, F2
	FADDD F2, F16, F16
	ADD  $16, R1
	SUB  $1, R2
	CBNZ R2, dial_norm_energy

	FCMPD $0.0, F16
	BLE  dial_norm_done

	FMOVD F16, F0
	FSQRTD F0, F0
	FMOVD $1.0, F2
	FDIVD F0, F2, F3
	MOVD $128, R2

dial_norm_apply:
	FMOVD (R0), F4
