	FMULD F3, F4, F4
	FMULD F3, F5, F5
	FMOVD F4, (R0)
	FMOVD F5, 8(R0)
	ADD  $16, R0
	SUB  $1, R2
	CBNZ R2, dial_norm_apply

dial_norm_done:
	RET

// func DialSimilarity128NEONAsm(left, right *complex128) float64
TEXT ·DialSimilarity128NEONAsm(SB), NOSPLIT, $0-24
