	MOVD right+8(FP), R1

	FMOVD $0.0, F16
	FMOVD $0.0, F17
	FMOVD $0.0, F18
	MOVD $128, R2

dial_sim_loop:
	FMOVD (R0), F0
	FMOVD 8(R0), F1
	FMOVD (R1), F2
	FMOVD 8(R1), F3
	FMULD F0, F2, F4
	FMULD F1, F3, F5
	FADDD F5, F4, F4
	FADDD F4, F16, F16
	FMULD F0, F0, F4
	FMULD F1, F1, F5
	FADDD F5, F4, F4
	FADDD F4, F17, F17
	FMULD F2, F2, F4
	FMULD F3, F3, F5
	FADDD F5, F4, F4
	FADDD F4, F18, F18
	ADD  $16, R0
	ADD  $16, R1
	SUB  $1, R2
	CBNZ R2, dial_sim_loop

	FMULD F17, F18, F19
	FCMPD $0.0, F19
	BLE  dial_sim_zero
	FSQRTD F17, F17
	FSQRTD F18, F18
	FMULD F18, F17, F17
	FDIVD F17, F16, F16
	FMOVD F16, ret+16(FP)
	RET

dial_sim_zero:
