	FSUBD F7, F6, F6
	FMULD F4, F30, F4
	FMULD F5, F29, F5
	FADDD F5, F4, F4
	FMOVD F6, (R0)
	FMOVD F4, 8(R0)
	ADD  $16, R1
	ADD  $16, R0
	SUB  $1, R2
	CBNZ R2, dial_rot_loop

	RET

